<p data-start="415" data-end="455">Türkiye’de yapılan başlıca kış sporları:</p>
<ul data-start="457" data-end="863">
<li data-start="457" data-end="555">
<p data-start="459" data-end="555"><strong data-start="459" data-end="482">Alp disiplini kayak</strong></p>
</li>
<li data-start="556" data-end="678">
<p data-start="558" data-end="678"><strong data-start="558" data-end="571">Snowboard</strong></p>
</li>
<li data-start="556" data-end="678">
<p data-start="558" data-end="678"><strong data-start="681" data-end="703">Kızak / kar kızağı</strong></p>
</li>
<li data-start="706" data-end="737">
<p data-start="708" data-end="737"><strong data-start="708" data-end="735">Kar motoru (snowmobile)</strong></p>
</li>
<li data-start="738" data-end="756">
<p data-start="740" data-end="756"><strong data-start="740" data-end="754">Buz pateni</strong></p>
</li>
<li data-start="757" data-end="816">
<p data-start="759" data-end="816"><strong data-start="759" data-end="814">Kar raftingi, kar yürüyüşü (snow hiking / trekking)</strong></p>
